/* cards.js — Questions vrai/faux (5+ par nœud). Révision FSRS + tests de validation. */
window.NEXUS_CARDS = [
  {"id":"f_e3_1","skill":"escalade","node":"e3","stmt":"En escalade, on grimpe principalement avec la force des bras.","truth":false,"explain":"Faux. On grimpe surtout avec les jambes : bien plus puissantes et endurantes. Les bras servent à l'équilibre et à la traction finale."},
  {"id":"f_e3_2","skill":"escalade","node":"e3","stmt":"La carre interne du chausson (côté gros orteil) est l'appui de référence.","truth":true,"explain":"Vrai. Précise et puissante, c'est l'appui le plus utilisé pour pousser sur les prises de pied."},
  {"id":"f_e3_3","skill":"escalade","node":"e3","stmt":"Lever le talon améliore l'adhérence du chausson sur un appui.","truth":false,"explain":"Faux. C'est l'inverse : garder le talon BAS et charger verticalement le pied augmente la friction."},
  {"id":"f_e4_1","skill":"escalade","node":"e4","stmt":"Le « crux » désigne le mouvement le plus difficile d'un bloc.","truth":true,"explain":"Vrai. C'est le passage clé autour duquel s'organise toute la méthode."},
  {"id":"f_e4_2","skill":"escalade","node":"e4","stmt":"Déplacer ses pieds ne change jamais la tenue d'une prise de main.","truth":false,"explain":"Faux. Déplacer les pieds change la direction de la résultante : une prise « inutilisable » peut alors tenir."},
  {"id":"f_e6_1","skill":"escalade","node":"e6","stmt":"Le « point mort » est l'instant idéal pour saisir la prise dans un mouvement dynamique.","truth":true,"explain":"Vrai. Au sommet de la trajectoire, le corps est en quasi-apesanteur : la force nécessaire est minimale."},
  {"id":"f_e6_2","skill":"escalade","node":"e6","stmt":"La puissance d'un jeté vient surtout des bras.","truth":false,"explain":"Faux. Elle vient surtout de l'extension explosive des JAMBES, aidée par le cycle étirement-raccourcissement."},
  {"id":"f_e8_1","skill":"escalade","node":"e8","stmt":"Le huit doublé se défait facilement même après une grosse chute.","truth":true,"explain":"Vrai. C'est un de ses avantages, avec sa solidité et sa vérification d'un coup d'œil."},
  {"id":"f_e8_2","skill":"escalade","node":"e8","stmt":"Si on connaît bien son nœud, la vérification mutuelle est facultative.","truth":false,"explain":"Faux. La vérification mutuelle grimpeur ↔ assureur est systématique : aucun nœud connu n'en dispense."},
  {"id":"f_e1_1","skill":"escalade","node":"e1","stmt":"La sécurité en escalade tient au maillon le plus faible de la chaîne d'assurage.","truth":true,"explain":"Vrai. Une faiblesse à n'importe quel niveau (baudrier, nœud, corde, points, appareil) compromet tout."},
  {"id":"f_m1_1","skill":"meca","node":"m1","stmt":"Un boulon doit être serré « le plus fort possible » pour bien tenir.","truth":false,"explain":"Faux. Il se serre à un COUPLE précis (N·m). Trop = rupture ; pas assez = desserrage."},
  {"id":"f_m1_2","skill":"meca","node":"m1","stmt":"Un cric suffit à maintenir un véhicule pendant qu'on travaille dessous.","truth":false,"explain":"Faux. Un cric lève mais ne maintient pas : on double TOUJOURS avec des chandelles."},
  {"id":"f_m1_3","skill":"meca","node":"m1","stmt":"On serre les assemblages multi-vis « en croix » pour répartir la précharge.","truth":true,"explain":"Vrai. Cela évite de voiler la pièce, souvent en plusieurs passes croissantes."},
  {"id":"f_m2_1","skill":"meca","node":"m2","stmt":"L'huile moteur sert uniquement à lubrifier.","truth":false,"explain":"Faux. Cinq fonctions : lubrifier, refroidir, nettoyer, protéger, étanchéifier."},
  {"id":"f_m2_2","skill":"meca","node":"m2","stmt":"Dans « 5W-30 », le 30 décrit le comportement de l'huile à chaud.","truth":true,"explain":"Vrai. 5W = à froid (winter), 30 = à chaud."},
  {"id":"f_m4_1","skill":"meca","node":"m4","stmt":"La plupart des pannes électriques auto viennent de composants morts.","truth":false,"explain":"Faux. Le plus souvent ce sont des résistances de contact : corrosion, cosse desserrée, mauvaise masse."},
  {"id":"f_m4_2","skill":"meca","node":"m4","stmt":"On peut remplacer un fusible par un calibre supérieur s'il refond souvent.","truth":false,"explain":"Faux. Jamais : un calibre supérieur supprime la protection et risque l'incendie. Cherche le défaut en aval."},
  {"id":"f_m5_1","skill":"meca","node":"m5","stmt":"Un code défaut OBD indique toujours la pièce exacte à remplacer.","truth":false,"explain":"Faux. Il pointe un symptôme, pas toujours la cause. On remonte du code à la vraie cause par des mesures."},
  {"id":"f_m5_2","skill":"meca","node":"m5","stmt":"Une correction d'injection fortement positive trahit souvent une prise d'air.","truth":true,"explain":"Vrai. Le trim signale un « manque de carburant » perçu, souvent dû à une prise d'air."},
  {"id":"f_m6_1","skill":"meca","node":"m6","stmt":"Sur un moteur « à interférence », une rupture de courroie peut plier les soupapes.","truth":true,"explain":"Vrai. Les courses soupapes/pistons se recoupent ; seule la distribution les sépare."},
  {"id":"f_m7_1","skill":"meca","node":"m7","stmt":"En réfection, une pièce usée se juge à l'œil, pas à la mesure.","truth":false,"explain":"Faux. On mesure au micromètre : une pièce n'est hors d'usage que si elle sort de sa tolérance."},
  {"id":"f_s1_1","skill":"survie","node":"s1","stmt":"En survie, trouver de la nourriture est prioritaire sur l'abri et l'eau.","truth":false,"explain":"Faux. Règle des 3 : protection et eau priment LARGEMENT (on tient ~3 semaines sans manger)."},
  {"id":"f_s1_2","skill":"survie","node":"s1","stmt":"Des vêtements mouillés accélèrent fortement la perte de chaleur.","truth":true,"explain":"Vrai. L'eau conduit la chaleur ~25× plus vite que l'air : rester sec est vital."},
  {"id":"f_s1_3","skill":"survie","node":"s1","stmt":"Face à un imprévu en nature, le premier réflexe utile est d'agir vite.","truth":false,"explain":"Faux. Méthode STOP : Stop, Think, Observe, Plan. Réfléchir prime ; la panique tue plus que le froid."},
  {"id":"f_s4_1","skill":"survie","node":"s4","stmt":"Isoler le sol sous soi est souvent plus important que le toit de l'abri.","truth":true,"explain":"Vrai. Allongé, le corps perd énormément de chaleur par conduction vers le sol froid."},
  {"id":"f_s4_2","skill":"survie","node":"s4","stmt":"Un grand abri se réchauffe mieux qu'un petit.","truth":false,"explain":"Faux. Un petit volume se réchauffe avec la chaleur du corps ; un grand ne se réchauffe jamais."},
  {"id":"f_s6_1","skill":"survie","node":"s6","stmt":"L'azimut est l'angle mesuré depuis le nord vers une direction visée.","truth":true,"explain":"Vrai. De 0 à 360° dans le sens horaire ; déterminé sur la carte, suivi à la boussole."},
  {"id":"f_s6_2","skill":"survie","node":"s6","stmt":"On peut ignorer la déclinaison magnétique sans conséquence sur de longues distances.","truth":false,"explain":"Faux. L'écart nord magnétique/géographique crée une erreur : ~17 m par km et par degré."},
  {"id":"f_a1_1","skill":"apiculture","node":"a1","stmt":"C'est l'alimentation (gelée royale), pas la génétique, qui fait d'une larve une reine.","truth":true,"explain":"Vrai. Même génome qu'une ouvrière : l'alimentation décide (mécanisme épigénétique)."},
  {"id":"f_a1_2","skill":"apiculture","node":"a1","stmt":"Un couvain « en mosaïque » (alvéoles vides dispersées) est signe de bonne santé.","truth":false,"explain":"Faux. C'est un signal d'alerte. Un couvain SAIN est compact et homogène."},
  {"id":"f_a1_3","skill":"apiculture","node":"a1","stmt":"Une ouvrière change de tâche en vieillissant (nettoyeuse, nourrice... butineuse).","truth":true,"explain":"Vrai. C'est le polyéthisme d'âge : il répartit les forces sans coordination centrale."},
  {"id":"f_a6_1","skill":"apiculture","node":"a6","stmt":"L'essaimage est une maladie qu'il faut éradiquer.","truth":false,"explain":"Faux. C'est le mode de reproduction naturel de la colonie. On l'anticipe et on le gère, on ne le supprime pas."},
  {"id":"f_a6_2","skill":"apiculture","node":"a6","stmt":"On évite d'ouvrir une ruche en hiver.","truth":true,"explain":"Vrai. La colonie forme une grappe thermorégulée ; chaque ouverture la refroidit."},
  {"id":"f_a7_1","skill":"apiculture","node":"a7","stmt":"On peut récolter le miel avant qu'il soit operculé sans risque.","truth":false,"explain":"Faux. Un miel non operculé est trop humide et risque de fermenter. On récolte le miel mûr."},
  {"id":"f_a7_2","skill":"apiculture","node":"a7","stmt":"Seule une larve de moins de 3 jours peut devenir une reine.","truth":true,"explain":"Vrai. Au-delà, le destin d'ouvrière est scellé : c'est le verrou de l'élevage de reines."},
  {"id":"f_b1_1","skill":"bois","node":"b1","stmt":"Porter des gants protège la main sur une machine rotative.","truth":false,"explain":"Faux. Dangereux : un gant happé entraîne la main. Gants = manutention uniquement."},
  {"id":"f_b1_2","skill":"bois","node":"b1","stmt":"Le rebond (kickback) survient quand la pièce se coince sur la lame.","truth":true,"explain":"Vrai. L'outil projette alors la pièce vers l'opérateur. Causes : pincement, guide mal réglé, pièce mal tenue."},
  {"id":"f_b2_1","skill":"bois","node":"b2","stmt":"Travailler à contre-fil donne une coupe plus nette que dans le sens du fil.","truth":false,"explain":"Faux. À contre-fil le bois s'arrache et éclate. On coupe net DANS le sens du fil."},
  {"id":"f_b2_2","skill":"bois","node":"b2","stmt":"Un outil bien affûté est plus sûr qu'un outil émoussé.","truth":true,"explain":"Vrai. Il coupe où on le dirige sans forcer ni déraper."},
  {"id":"f_b3_1","skill":"bois","node":"b3","stmt":"En traçage, mieux vaut mesurer chaque cote depuis un bord différent.","truth":false,"explain":"Faux. Principe de référence unique : tout se mesure depuis UNE face et UN chant, sinon les erreurs s'accumulent."},
  {"id":"f_b3_2","skill":"bois","node":"b3","stmt":"Une pointe à tracer est plus précise qu'un crayon pour un ouvrage fin.","truth":true,"explain":"Vrai. Le crayon a une épaisseur ; la pointe trace fin et amorce la coupe en sectionnant les fibres."},
  {"id":"f_b5_1","skill":"bois","node":"b5","stmt":"Le bois colle plus solidement en bois de bout qu'en long-bois.","truth":false,"explain":"Faux. L'inverse : le bois de bout est poreux et « pompe » la colle. On maximise le long-bois."},
  {"id":"f_b5_2","skill":"bois","node":"b5","stmt":"Un bon assemblage entre « à frottement dur » : sans jeu mais sans fendre le bois.","truth":true,"explain":"Vrai. Montable au maillet doux ; l'ajustage final se fait au ciseau par petites passes."},
  {"id":"f_b6_1","skill":"bois","node":"b6","stmt":"Plus on serre fort un collage, plus le joint est solide.","truth":false,"explain":"Faux. Une pression excessive chasse la colle (joint « affamé »), donc faible. Pression régulière, pas maximale."},
  {"id":"f_b6_2","skill":"bois","node":"b6","stmt":"Le « montage à blanc » se fait sans colle, avant l'encollage.","truth":true,"explain":"Vrai. Il vérifie que tout ferme et prépare les serre-joints, car la colle a un temps ouvert limité."},
  {"id":"f_b7_1","skill":"bois","node":"b7","stmt":"On peut fixer rigidement un large plateau massif en travers de son fil.","truth":false,"explain":"Faux. Le bois travaille en largeur ; le bloquer le fait fendre. On utilise des fixations qui autorisent le glissement."},
  {"id":"f_b7_2","skill":"bois","node":"b7","stmt":"En finition, on ponce en grains croissants (du grossier au fin).","truth":true,"explain":"Vrai. Chaque grain efface les rayures du précédent ; on dépoussière entre chaque passe."},
  {"id":"q_e2_1","skill":"escalade","node":"e2","stmt":"En moulinette, l'assureur peut lâcher la corde côté freinage tant que le grimpeur monte.","truth":false,"explain":"Faux. La main de freinage ne quitte JAMAIS la corde, même quand le grimpeur progresse sans à-coup. C'est la règle absolue de l'assurage."},
  {"id":"q_e2_2","skill":"escalade","node":"e2","stmt":"Reprendre le mou trop lentement augmente la hauteur de chute potentielle.","truth":true,"explain":"Vrai. Du mou non repris = le grimpeur tombe plus bas avant que la corde ne le retienne. On reprend au fur et à mesure."},
  {"id":"q_e2_3","skill":"escalade","node":"e2","stmt":"La vérification mutuelle (nœud + système d'assurage) se fait avant chaque montée.","truth":true,"explain":"Vrai. Grimpeur et assureur se contrôlent mutuellement systématiquement, avant de quitter le sol."},
  {"id":"q_e2_4","skill":"escalade","node":"e2","stmt":"L'assurage s'apprend très bien seul, à partir d'une vidéo.","truth":false,"explain":"Faux. L'assurage engage la vie du grimpeur : il s'apprend encadré, en présence d'un professionnel ou d'un club. Cet encadré ne remplace pas une formation."},
  {"id":"q_e2_5","skill":"escalade","node":"e2","stmt":"Parer une chute consiste à protéger la tête et le buste du grimpeur avant qu'il ne soit sur la corde.","truth":true,"explain":"Vrai. La parade protège pendant les premiers mouvements, avant que la corde ne soit efficace."},
  {"id":"q_e5_1","skill":"escalade","node":"e5","stmt":"En tête, une chute fait tomber le grimpeur d'environ le double de la hauteur au-dessus de sa dernière dégaine.","truth":true,"explain":"Vrai. On tombe la hauteur au-dessus du point + la même longueur en dessous, plus l'allongement. D'où le sérieux de la grimpe en tête."},
  {"id":"q_e5_2","skill":"escalade","node":"e5","stmt":"Passer la corde derrière la jambe ne présente aucun risque en tête.","truth":false,"explain":"Faux. La corde derrière la jambe peut, lors d'une chute, retourner le grimpeur tête en bas. C'est un danger classique à éviter."},
  {"id":"q_e5_3","skill":"escalade","node":"e5","stmt":"Le « tirage » désigne le frottement de la corde qui gêne la progression en tête.","truth":true,"explain":"Vrai. Un mauvais cheminement de corde crée du tirage qui freine et fatigue ; on l'évite avec des dégaines bien placées."},
  {"id":"q_e5_4","skill":"escalade","node":"e5","stmt":"La grimpe en tête peut s'apprendre seul sans encadrement, c'est juste de la moulinette plus haut.","truth":false,"explain":"Faux. La chute en tête, le mousquetonnage et la gestion du tirage demandent un apprentissage encadré. Cet encadré ne remplace pas une formation."},
  {"id":"q_e5_5","skill":"escalade","node":"e5","stmt":"Un mousquetonnage « à l'envers » (doigt vers le rocher) peut faire dégrafer la corde lors d'une chute.","truth":true,"explain":"Vrai. Une dégaine mal orientée peut se décliper en cas de chute : on vérifie le sens du doigt du mousqueton."},
  {"id":"q_e7_1","skill":"escalade","node":"e7","stmt":"En grande voie, on peut s'auto-assurer au relais avec une seule longe sans vérification.","truth":false,"explain":"Faux. La sécurité au relais repose sur la redondance et la vérification : un seul point ou une longe non contrôlée est dangereux. Formation indispensable."},
  {"id":"q_e7_2","skill":"escalade","node":"e7","stmt":"Lors d'un rappel, le nœud en bout de corde évite de passer au-delà des brins.","truth":true,"explain":"Vrai. Les nœuds d'arrêt en bout de corde empêchent de descendre en rappel au-delà de la corde — accident mortel classique."},
  {"id":"q_e7_3","skill":"escalade","node":"e7","stmt":"La gestion d'une cordée en grande voie est essentiellement une question de force physique.","truth":false,"explain":"Faux. C'est avant tout de l'organisation, de la communication et de la gestion des risques (relais, rappels, météo, horaires)."},
  {"id":"q_e7_4","skill":"escalade","node":"e7","stmt":"La grande voie ajoute des risques (relais, rappel, engagement) qui exigent une formation spécifique.","truth":true,"explain":"Vrai. Cet encadré pose le cadre mais la grande voie s'apprend progressivement, encadré, après avoir maîtrisé la couenne."},
  {"id":"q_e7_5","skill":"escalade","node":"e7","stmt":"En grande voie, on peut négliger la météo si la voie est courte.","truth":false,"explain":"Faux. Un orage ou un refroidissement piège une cordée en paroi. La météo se vérifie toujours, quelle que soit la longueur."},
  {"id":"q_m3_1","skill":"meca","node":"m3","stmt":"Le freinage est un système de sécurité critique : une erreur peut être mortelle.","truth":true,"explain":"Vrai. C'est pourquoi, en cas de doute, le freinage se confie à un professionnel. Cet encadré informe mais n'est pas un tutoriel d'intervention."},
  {"id":"q_m3_2","skill":"meca","node":"m3","stmt":"Une pédale de frein « spongieuse » ou molle peut signaler de l'air dans le circuit.","truth":true,"explain":"Vrai. De l'air dans le liquide (compressible) rend la pédale spongieuse — d'où la purge. C'est un signal à ne jamais ignorer."},
  {"id":"q_m3_3","skill":"meca","node":"m3","stmt":"On peut rouler sans risque avec des plaquettes au témoin d'usure tant qu'on entend pas de bruit.","truth":false,"explain":"Faux. Au témoin, les plaquettes sont en fin de vie ; attendre le bruit métallique, c'est déjà attaquer le disque. On remplace avant."},
  {"id":"q_m3_4","skill":"meca","node":"m3","stmt":"Le liquide de frein absorbe l'humidité avec le temps, ce qui abaisse son point d'ébullition.","truth":true,"explain":"Vrai. Le liquide est hygroscopique : l'eau absorbée peut bouillir au freinage intense et créer une perte de freinage. D'où son remplacement périodique."},
  {"id":"q_m3_5","skill":"meca","node":"m3","stmt":"Après avoir changé les plaquettes, il est inutile de pomper la pédale avant de rouler.","truth":false,"explain":"Faux. On pompe pour replaquer les pistons sur les plaquettes neuves : sinon, la première pédale est dans le vide. Détail critique."},
  {"id":"q_s2_1","skill":"survie","node":"s2","stmt":"Filtrer une eau trouble la rend automatiquement potable.","truth":false,"explain":"Faux. Le filtrage clarifie (enlève les particules) mais ne tue pas forcément les micro-organismes. Il faut ensuite désinfecter (ébullition…)."},
  {"id":"q_s2_2","skill":"survie","node":"s2","stmt":"Porter l'eau à ébullition est un moyen fiable de tuer la majorité des pathogènes.","truth":true,"explain":"Vrai. L'ébullition est l'une des méthodes les plus sûres pour rendre l'eau biologiquement potable."},
  {"id":"q_s2_3","skill":"survie","node":"s2","stmt":"Une eau claire de source de montagne est toujours sans danger.","truth":false,"explain":"Faux. Même limpide, elle peut contenir des parasites (un animal mort en amont suffit). La limpidité ne garantit pas la potabilité."},
  {"id":"q_s2_4","skill":"survie","node":"s2","stmt":"L'eau de pluie recueillie proprement est généralement plus sûre qu'une eau stagnante.","truth":true,"explain":"Vrai. L'eau de pluie collectée directement est en général plus sûre qu'une mare stagnante, mais la prudence reste de mise."},
  {"id":"q_s2_5","skill":"survie","node":"s2","stmt":"En situation réelle, mieux vaut se former aux techniques de purification avant d'en avoir besoin.","truth":true,"explain":"Vrai. Cet encadré donne les principes ; la pratique (filtres, pastilles, ébullition) se prépare à l'avance, pas dans l'urgence."},
  {"id":"q_s3_1","skill":"survie","node":"s3","stmt":"Le feu a besoin de trois éléments : combustible, comburant (oxygène) et chaleur.","truth":true,"explain":"Vrai. C'est le « triangle du feu ». Retirer un seul élément l'éteint — principe de base de l'allumage et de l'extinction."},
  {"id":"q_s3_2","skill":"survie","node":"s3","stmt":"On démarre un feu directement avec de grosses bûches pour qu'il dure.","truth":false,"explain":"Faux. On part de l'amadou (fin, sec) puis du petit bois, en augmentant progressivement. Une grosse bûche seule ne prend pas."},
  {"id":"q_s3_3","skill":"survie","node":"s3","stmt":"Le bois mort encore sur l'arbre (debout) est souvent plus sec que le bois au sol.","truth":true,"explain":"Vrai. Le bois au sol absorbe l'humidité ; le bois mort sur pied reste plus sec, meilleur pour démarrer."},
  {"id":"q_s3_4","skill":"survie","node":"s3","stmt":"Un feu peut être laissé sans surveillance s'il est petit.","truth":false,"explain":"Faux. Tout feu non surveillé peut se propager. On le contient (cercle de pierres, sol dégagé) et on l'éteint complètement avant de partir."},
  {"id":"q_s3_5","skill":"survie","node":"s3","stmt":"L'humidité du bois est le principal facteur d'échec d'un allumage.","truth":true,"explain":"Vrai. Un bois humide ne prend pas ou fume sans flamme. Trouver du combustible sec est souvent le vrai défi."},
  {"id":"q_s5_1","skill":"survie","node":"s5","stmt":"Face à une hémorragie abondante, la priorité est de comprimer fortement la plaie.","truth":true,"explain":"Vrai. La compression directe et ferme est le premier geste. Cet encadré informe mais ne remplace pas une formation aux premiers secours (PSC1)."},
  {"id":"q_s5_2","skill":"survie","node":"s5","stmt":"La Position Latérale de Sécurité (PLS) s'utilise sur une personne inconsciente qui respire.","truth":true,"explain":"Vrai. La PLS protège les voies aériennes d'une personne inconsciente mais qui respire, en attendant les secours."},
  {"id":"q_s5_3","skill":"survie","node":"s5","stmt":"En cas d'hypothermie sévère, il faut réchauffer la victime brutalement et la frictionner vigoureusement.","truth":false,"explain":"Faux. Le réchauffement doit être progressif et doux ; un réchauffement brutal peut être dangereux. La prudence et l'appel aux secours priment."},
  {"id":"q_s5_4","skill":"survie","node":"s5","stmt":"Connaître le numéro d'urgence et savoir décrire sa position fait partie des premiers secours.","truth":true,"explain":"Vrai. Alerter efficacement (qui, où, quoi) est un maillon essentiel de la chaîne de secours."},
  {"id":"q_s5_5","skill":"survie","node":"s5","stmt":"Les premiers secours s'improvisent très bien le moment venu, sans formation préalable.","truth":false,"explain":"Faux. Les bons gestes s'apprennent et se répètent en formation (PSC1). Cet encadré sensibilise, il ne forme pas."},
  {"id":"q_s7_1","skill":"survie","node":"s7","stmt":"En expédition autonome, la gestion des ressources (eau, nourriture, énergie) se planifie à l'avance.","truth":true,"explain":"Vrai. L'autonomie prolongée repose sur une planification rigoureuse : consommation, points de réapprovisionnement, marges."},
  {"id":"q_s7_2","skill":"survie","node":"s7","stmt":"Plus une expédition est longue, moins la navigation a d'importance.","truth":false,"explain":"Faux. Sur la durée, les petites erreurs de navigation s'accumulent. Le suivi de cap et la position sont d'autant plus critiques."},
  {"id":"q_s7_3","skill":"survie","node":"s7","stmt":"Prévoir une marge de sécurité (temps, vivres) est un principe de base de l'expédition.","truth":true,"explain":"Vrai. La marge absorbe les imprévus (météo, blessure, retard). Partir « au plus juste » est un piège classique."},
  {"id":"q_s7_4","skill":"survie","node":"s7","stmt":"L'autonomie prolongée est le niveau le plus exigeant : elle combine toutes les compétences précédentes.","truth":true,"explain":"Vrai. Eau, feu, abri, orientation, secours : tout converge. Elle se construit progressivement, pas du jour au lendemain."},
  {"id":"q_s7_5","skill":"survie","node":"s7","stmt":"En autonomie, il est inutile de prévenir quiconque de son itinéraire puisqu'on est indépendant.","truth":false,"explain":"Faux. Justement parce qu'on est isolé, laisser son itinéraire et ses dates à un tiers est vital pour déclencher les secours en cas de problème."},
  {"id":"q_a2_1","skill":"apiculture","node":"a2","stmt":"Détenir des ruches impose généralement une déclaration auprès des autorités compétentes.","truth":true,"explain":"Vrai. La déclaration de rucher est une obligation dans de nombreux pays (suivi sanitaire). Les modalités exactes sont à vérifier auprès de l'autorité locale."},
  {"id":"q_a2_2","skill":"apiculture","node":"a2","stmt":"Il n'existe nulle part de règles de distance entre un rucher et le voisinage ou la voie publique.","truth":false,"explain":"Faux. Beaucoup de localités imposent des distances ou des haies. Les règles précises varient — à vérifier en mairie/réglementation locale."},
  {"id":"q_a2_3","skill":"apiculture","node":"a2","stmt":"Tenir un registre d'élevage / de traitements fait souvent partie des obligations apicoles.","truth":true,"explain":"Vrai. Le registre (traitements, déplacements) est fréquemment requis pour la traçabilité sanitaire. Détails selon réglementation locale."},
  {"id":"q_a2_4","skill":"apiculture","node":"a2","stmt":"La réglementation apicole est identique partout, inutile de se renseigner localement.","truth":false,"explain":"Faux. Elle varie selon les pays et collectivités. Cet encadré invite justement à vérifier les obligations de son secteur."},
  {"id":"q_a2_5","skill":"apiculture","node":"a2","stmt":"La déclaration de ruches sert notamment au suivi sanitaire en cas d'épidémie.","truth":true,"explain":"Vrai. Le recensement permet d'alerter et d'agir en cas de maladie (loque, frelon…) dans une zone."},
  {"id":"q_a3_1","skill":"apiculture","node":"a3","stmt":"L'enfumoir agit en perturbant la communication des abeilles par phéromones d'alarme.","truth":true,"explain":"Vrai. La fumée masque les phéromones d'alerte et déclenche un réflexe de gorgement, ce qui calme la colonie."},
  {"id":"q_a3_2","skill":"apiculture","node":"a3","stmt":"Une protection (combinaison, voile, gants) est facultative pour un débutant.","truth":false,"explain":"Faux. La protection est essentielle, surtout en débutant : une piqûre près de l'œil ou une réaction allergique peut être grave."},
  {"id":"q_a3_3","skill":"apiculture","node":"a3","stmt":"En cas d'allergie connue au venin d'abeille, des précautions médicales spécifiques s'imposent.","truth":true,"explain":"Vrai. Une allergie au venin peut provoquer un choc anaphylactique. Un avis médical et un protocole d'urgence sont indispensables."},
  {"id":"q_a3_4","skill":"apiculture","node":"a3","stmt":"On retire un dard en le pinçant entre deux doigts pour bien l'attraper.","truth":false,"explain":"Faux. Pincer presse la glande et injecte plus de venin. On le racle (ongle, carte) latéralement pour l'enlever sans presser."},
  {"id":"q_a3_5","skill":"apiculture","node":"a3","stmt":"Un enfumoir doit produire une fumée froide et non des flammes.","truth":true,"explain":"Vrai. Une fumée froide calme sans brûler les abeilles ; des flammes ou une fumée brûlante les agressent."},
  {"id":"q_a4_1","skill":"apiculture","node":"a4","stmt":"On ouvre une ruche de préférence par beau temps, en journée, quand les butineuses sont aux champs.","truth":true,"explain":"Vrai. Par beau temps et en pleine activité, il y a moins d'abeilles dans la ruche et elles sont plus calmes."},
  {"id":"q_a4_2","skill":"apiculture","node":"a4","stmt":"Des gestes brusques et rapides rassurent la colonie pendant la visite.","truth":false,"explain":"Faux. Les gestes lents et calmes limitent le stress de la colonie ; la brusquerie déclenche l'agressivité."},
  {"id":"q_a4_3","skill":"apiculture","node":"a4","stmt":"Lire un cadre, c'est savoir distinguer couvain, pollen et réserves de miel.","truth":true,"explain":"Vrai. La lecture du cadre (couvain compact, couronnes de pollen et de miel) est la compétence centrale de la visite."},
  {"id":"q_a4_4","skill":"apiculture","node":"a4","stmt":"Ouvrir une colonie sans aucune notion préalable est sans risque pour le débutant et les abeilles.","truth":false,"explain":"Faux. Mal manipuler stresse la colonie, écrase des abeilles, voire la reine. La visite s'apprend accompagné. Cet encadré ne remplace pas un parrain/formation."},
  {"id":"q_a4_5","skill":"apiculture","node":"a4","stmt":"Repérer la présence de couvain frais (œufs/jeunes larves) indique une reine active récemment.","truth":true,"explain":"Vrai. Des œufs signifient que la reine pondait il y a quelques jours — un indice clé de l'état de la colonie."},
  {"id":"q_a5_1","skill":"apiculture","node":"a5","stmt":"Le varroa est un parasite majeur qui affaiblit les colonies et transmet des virus.","truth":true,"explain":"Vrai. Varroa destructor est l'un des principaux fléaux apicoles ; sa surveillance et sa gestion sont essentielles."},
  {"id":"q_a5_2","skill":"apiculture","node":"a5","stmt":"Une colonie peut être laissée sans aucun suivi sanitaire sans conséquence.","truth":false,"explain":"Faux. Sans surveillance (varroa, loques, frelon), une colonie peut s'effondrer ou contaminer les ruchers voisins."},
  {"id":"q_a5_3","skill":"apiculture","node":"a5","stmt":"Les traitements et leur calendrier sont encadrés et dépendent de la réglementation et du contexte local.","truth":true,"explain":"Vrai. Produits autorisés, doses et périodes varient ; à vérifier auprès des sources officielles et vétérinaires/techniciens sanitaires apicoles."},
  {"id":"q_a5_4","skill":"apiculture","node":"a5","stmt":"Certaines maladies du couvain sont à déclaration obligatoire dans de nombreux pays.","truth":true,"explain":"Vrai. Des maladies graves (ex. loque américaine) sont souvent à déclaration obligatoire pour limiter la propagation."},
  {"id":"q_a5_5","skill":"apiculture","node":"a5","stmt":"Compter les varroas (sur lange ou par comptage) aide à décider d'un traitement.","truth":true,"explain":"Vrai. L'estimation de l'infestation guide la décision et le moment d'intervention plutôt que de traiter à l'aveugle."},
  {"id":"q_b4_1","skill":"bois","node":"b4","stmt":"Le rebond (kickback) d'une scie circulaire peut projeter la machine ou la pièce vers l'opérateur.","truth":true,"explain":"Vrai. Le rebond est le danger majeur de la scie circulaire ; couteau diviseur, bonne prise et pièce bien tenue le limitent. Formation recommandée."},
  {"id":"q_b4_2","skill":"bois","node":"b4","stmt":"On peut retirer le carter de protection d'une scie pour mieux voir la coupe.","truth":false,"explain":"Faux. Les protections (carter, couteau diviseur) sont là pour sauver des doigts. On ne les retire jamais."},
  {"id":"q_b4_3","skill":"bois","node":"b4","stmt":"Une défonceuse se guide toujours dans le sens qui plaque l'outil contre le bois (sens conventionnel).","truth":true,"explain":"Vrai. Le sens d'avance correct évite que l'outil ne « parte » ; le sens inversé (avalant) est dangereux et réservé à des cas maîtrisés."},
  {"id":"q_b4_4","skill":"bois","node":"b4","stmt":"Une pièce mal fixée est l'une des principales causes d'accident à l'électroportatif.","truth":true,"explain":"Vrai. Une pièce qui bouge happe l'outil ou la main. On serre toujours la pièce (serre-joints) avant d'usiner."},
  {"id":"q_b4_5","skill":"bois","node":"b4","stmt":"Les outils électroportatifs sont sans danger tant qu'on est prudent, la formation est superflue.","truth":false,"explain":"Faux. Leur énergie et leur vitesse en font les outils les plus dangereux de l'atelier. Cet encadré sensibilise ; la prise en main s'apprend encadré."},
  {"id":"q_e3_a","skill":"escalade","node":"e3","stmt":"Coller le bassin à la paroi rapproche le centre de gravité du mur et soulage les bras.","truth":true,"explain":"Vrai. Bassin près du mur = poids transféré dans les pieds, moins de bras de levier sur les doigts."},
  {"id":"q_e3_b","skill":"escalade","node":"e3","stmt":"Une gomme de chausson sale accroche aussi bien qu'une gomme propre.","truth":false,"explain":"Faux. La poussière réduit fortement la friction ; on essuie/brosse la semelle avant de grimper."},
  {"id":"q_e4_a","skill":"escalade","node":"e4","stmt":"On lit un bloc en partant du crux et en construisant la séquence à rebours.","truth":true,"explain":"Vrai. On identifie le mouvement dur puis on remonte : dans quelle position faut-il y arriver ?"},
  {"id":"q_e4_b","skill":"escalade","node":"e4","stmt":"Une prise « plat » (sloper) tient surtout grâce à un bord franc à serrer.","truth":false,"explain":"Faux. Un sloper n'a pas de bord : il tient par friction et par le placement du corps SOUS la prise."},
  {"id":"q_e4_c","skill":"escalade","node":"e4","stmt":"Deux grimpeurs de morphologies différentes peuvent résoudre un bloc par des méthodes différentes.","truth":true,"explain":"Vrai. La méthode dépend de la taille, de l'envergure (indice d'Ape) et de la souplesse."},
  {"id":"q_e6_a","skill":"escalade","node":"e6","stmt":"Décomposer un jeté en marquant une pause après l'armé le rend plus puissant.","truth":false,"explain":"Faux. La pause dissipe l'énergie élastique stockée : un jeté armé-puis-lâché sans temps d'arrêt est plus puissant."},
  {"id":"q_e6_b","skill":"escalade","node":"e6","stmt":"Au-delà d'une certaine distance, un mouvement dynamique est plus économique qu'un statique.","truth":true,"explain":"Vrai. Le statique exige une longue contraction isométrique ; le dynamique exploite l'inertie."},
  {"id":"q_e6_c","skill":"escalade","node":"e6","stmt":"Lors d'un dyno, les quatre appuis quittent le mur.","truth":true,"explain":"Vrai. Le dyno est le cas extrême où le corps est entièrement en vol."},
  {"id":"q_e8_a","skill":"escalade","node":"e8","stmt":"Le cabestan a l'avantage de pouvoir se régler sans être complètement défait.","truth":true,"explain":"Vrai. C'est son intérêt au relais : on ajuste la longueur sans déconnecter."},
  {"id":"q_e8_b","skill":"escalade","node":"e8","stmt":"Un nœud d'arrêt en bout de corde est inutile en moulinette comme en rappel.","truth":false,"explain":"Faux. Il empêche la corde de filer hors de l'assureur ou de passer au-delà des brins en rappel — sécurité essentielle."},
  {"id":"q_e8_c","skill":"escalade","node":"e8","stmt":"Un nœud mal réalisé peut être plus dangereux que pas de nœud, car il donne une fausse confiance.","truth":true,"explain":"Vrai. D'où la vérification systématique : un nœud se contrôle visuellement à chaque fois."},
  {"id":"q_e1_a","skill":"escalade","node":"e1","stmt":"Le baudrier doit être bouclé selon les indications du fabricant, sangle repassée si requis.","truth":true,"explain":"Vrai. Un baudrier mal bouclé peut s'ouvrir sous charge. On suit la procédure du fabricant."},
  {"id":"q_e1_b","skill":"escalade","node":"e1","stmt":"Un matériel d'escalade qui a subi une grosse chute peut toujours être réutilisé sans contrôle.","truth":false,"explain":"Faux. Certains EPI (casque, parfois mousquetons) se contrôlent ou se réforment après un choc important."},
  {"id":"q_e1_c","skill":"escalade","node":"e1","stmt":"La date de péremption et l'état d'usure des EPI (corde, baudrier) doivent être surveillés.","truth":true,"explain":"Vrai. Les EPI textiles vieillissent ; usure, UV et chocs réduisent leur durée de vie."},
  {"id":"q_e1_d","skill":"escalade","node":"e1","stmt":"Le casque ne sert à rien en escalade puisqu'on tombe sur la corde.","truth":false,"explain":"Faux. Le casque protège des chutes de pierres et des chocs de la tête contre la paroi lors d'une chute."},
  {"id":"q_m1_a","skill":"meca","node":"m1","stmt":"Une clé à œil répartit mieux l'effort qu'une clé plate et abîme moins l'écrou.","truth":true,"explain":"Vrai. La clé à œil (6/12 pans) enserre l'écrou ; la clé plate ne prend que 2 faces et a tendance à riper."},
  {"id":"q_m1_b","skill":"meca","node":"m1","stmt":"Certaines vis à serrage angulaire sont à usage unique et doivent être remplacées.","truth":true,"explain":"Vrai. Les vis auto-cassantes (serrage à l'angle) se déforment plastiquement : remplacement obligatoire."},
  {"id":"q_m2_a","skill":"meca","node":"m2","stmt":"Un sous-gonflage des pneus augmente la consommation et l'échauffement.","truth":true,"explain":"Vrai. Un pneu sous-gonflé chauffe et augmente la résistance au roulement ; un sur-gonflage use le centre."},
  {"id":"q_m2_b","skill":"meca","node":"m2","stmt":"On peut ouvrir le bouchon du circuit de refroidissement à chaud sans risque.","truth":false,"explain":"Faux. Le circuit est sous pression à chaud : ouvrir projette du liquide brûlant. On attend le refroidissement."},
  {"id":"q_m2_c","skill":"meca","node":"m2","stmt":"Le filtre à huile se remplace à chaque vidange.","truth":true,"explain":"Vrai. Un filtre encrassé laisse circuler des impuretés ; on le change avec l'huile."},
  {"id":"q_m4_a","skill":"meca","node":"m4","stmt":"D'après la loi d'Ohm, U = R × I.","truth":true,"explain":"Vrai. Tension = résistance × intensité, la relation de base de tout circuit."},
  {"id":"q_m4_b","skill":"meca","node":"m4","stmt":"On mesure une intensité en branchant le multimètre en parallèle du circuit.","truth":false,"explain":"Faux. L'intensité se mesure en SÉRIE (le courant traverse l'appareil) ; la tension se mesure en parallèle."},
  {"id":"q_m4_c","skill":"meca","node":"m4","stmt":"Une masse corrodée peut provoquer des pannes diffuses et déroutantes.","truth":true,"explain":"Vrai. La masse est le retour commun : un mauvais contact crée des symptômes erratiques sur plusieurs circuits."},
  {"id":"q_m5_a","skill":"meca","node":"m5","stmt":"Le « freeze frame » enregistre les conditions du moteur au moment où le défaut est apparu.","truth":true,"explain":"Vrai. Régime, charge, température au moment du défaut : précieux pour reproduire et diagnostiquer."},
  {"id":"q_m5_b","skill":"meca","node":"m5","stmt":"Lire les données en direct (live data) n'apporte rien de plus que le code défaut.","truth":false,"explain":"Faux. Les valeurs en temps réel (capteurs, trims) sont souvent la clé pour distinguer la cause du symptôme."},
  {"id":"q_m5_c","skill":"meca","node":"m5","stmt":"La lettre d'un code OBD (P, B, C, U) indique le système concerné.","truth":true,"explain":"Vrai. P = groupe motopropulseur, B = carrosserie, C = châssis, U = réseau."},
  {"id":"q_m6_a","skill":"meca","node":"m6","stmt":"Sur un 4 temps, l'arbre à cames tourne à la moitié du régime du vilebrequin.","truth":true,"explain":"Vrai. Un cycle complet = 2 tours vilebrequin pour 1 tour d'arbre à cames."},
  {"id":"q_m6_b","skill":"meca","node":"m6","stmt":"On remplace la courroie de distribution seule, sans les galets ni le tendeur.","truth":false,"explain":"Faux. On remplace le kit complet (courroie + galets + tendeur) : un galet usé ruinerait la courroie neuve."},
  {"id":"q_m6_c","skill":"meca","node":"m6","stmt":"Une chaîne de distribution détendue peut « sauter » une dent et décaler le calage.","truth":true,"explain":"Vrai. D'où l'importance du tendeur et de la lubrification ; une chaîne lâche déphase la distribution."},
  {"id":"q_m6_d","skill":"meca","node":"m6","stmt":"Le calage se fait en amenant le moteur au point mort haut du cylindre 1 et en alignant les repères.","truth":true,"explain":"Vrai. PMH cylindre 1 + repères alignés (souvent avec des piges) = procédure de calage de référence."},
  {"id":"q_m7_a","skill":"meca","node":"m7","stmt":"On peut mélanger les chapeaux de paliers entre eux, ils sont interchangeables.","truth":false,"explain":"Faux. Ils sont usinés appariés avec leur bloc/bielle : jamais mélangés, sous peine de jeu incorrect."},
  {"id":"q_m7_b","skill":"meca","node":"m7","stmt":"La conicité d'un cylindre est une usure non uniforme sur sa hauteur.","truth":true,"explain":"Vrai. Le cylindre s'use davantage en haut (où le segment de feu travaille à chaud) : il devient conique."},
  {"id":"q_m7_c","skill":"meca","node":"m7","stmt":"Le Plastigauge sert à mesurer le jeu aux coussinets.","truth":true,"explain":"Vrai. Ce fil calibré écrasé révèle le jeu de fonctionnement des coussinets."},
  {"id":"q_m7_d","skill":"meca","node":"m7","stmt":"On peut monter un moteur à sec, sans huile d'assemblage, sans risque au démarrage.","truth":false,"explain":"Faux. L'huile d'assemblage protège les pièces au premier démarrage, avant que la pression d'huile s'établisse : indispensable."},
  {"id":"q_s1_a","skill":"survie","node":"s1","stmt":"L'air immobile emprisonné dans les fibres (laine, duvet) est un bon isolant.","truth":true,"explain":"Vrai. C'est l'air piégé qui isole, pas la matière : d'où l'efficacité des matériaux foisonnants."},
  {"id":"q_s1_b","skill":"survie","node":"s1","stmt":"Un sifflet est inutile car la voix porte aussi loin.","truth":false,"explain":"Faux. Un sifflet porte bien plus loin que la voix et fatigue moins : c'est un outil d'alerte essentiel."},
  {"id":"q_s4_a","skill":"survie","node":"s4","stmt":"Une litière sèche se comprime sous le poids et perd alors de son pouvoir isolant.","truth":true,"explain":"Vrai. Comprimée, elle perd l'air qui isole : on en met une épaisse couche pour compenser."},
  {"id":"q_s4_b","skill":"survie","node":"s4","stmt":"Construire son abri de nuit, épuisé, est préférable pour économiser le jour.","truth":false,"explain":"Faux. On construit tant qu'il fait jour et qu'on a de l'énergie ; un abri bâclé dans le noir échoue souvent."},
  {"id":"q_s4_c","skill":"survie","node":"s4","stmt":"Une paroi réfléchissante derrière un feu renvoie la chaleur vers l'abri.","truth":true,"explain":"Vrai. Le feu devant un abri ouvert + un réflecteur renvoie le rayonnement vers l'occupant."},
  {"id":"q_s6_a","skill":"survie","node":"s6","stmt":"Une « ligne d'arrêt » est un repère transversal qui signale qu'on est allé trop loin.","truth":true,"explain":"Vrai. Rivière, route ou crête transversale : la franchir indique le dépassement de l'objectif."},
  {"id":"q_s6_b","skill":"survie","node":"s6","stmt":"Un seul repère isolé suffit à confirmer sa position avec certitude.","truth":false,"explain":"Faux. On confirme avec plusieurs indices : un repère isolé peut tromper (deux sommets se ressemblent)."},
  {"id":"q_s6_c","skill":"survie","node":"s6","stmt":"Le GPS doit rester le seul moyen de navigation car il est infaillible.","truth":false,"explain":"Faux. Batterie, signal, casse : le GPS peut lâcher. Carte et boussole sont la sécurité de secours."},
  {"id":"q_a1_a","skill":"apiculture","node":"a1","stmt":"Un faux-bourdon (mâle) naît d'un œuf non fécondé.","truth":true,"explain":"Vrai. Haplodiploïdie : œuf non fécondé (haploïde) = mâle ; œuf fécondé = femelle."},
  {"id":"q_a1_b","skill":"apiculture","node":"a1","stmt":"La reine contrôle la colonie principalement par la force physique.","truth":false,"explain":"Faux. Elle régule par ses phéromones (dont la phéromone mandibulaire), pas par la force."},
  {"id":"q_a6_a","skill":"apiculture","node":"a6","stmt":"Poser les hausses à temps au printemps aide à prévenir l'essaimage.","truth":true,"explain":"Vrai. Donner de la place absorbe la croissance de population et retarde le passage en mode reproductif."},
  {"id":"q_a6_b","skill":"apiculture","node":"a6","stmt":"En période de grande miellée, une colonie forte ne stocke que quelques grammes par jour.","truth":false,"explain":"Faux. Elle peut stocker plusieurs kilos de nectar par jour ; un manque de place précipite l'essaimage."},
  {"id":"q_a6_c","skill":"apiculture","node":"a6","stmt":"Des cellules royales en construction annoncent souvent un essaimage.","truth":true,"explain":"Vrai. C'est un signe précurseur : la colonie prépare une nouvelle reine."},
  {"id":"q_a7_a","skill":"apiculture","node":"a7","stmt":"On extrait le miel par centrifugation, ce qui détruit les rayons de cire.","truth":false,"explain":"Faux. La centrifugation vide les alvéoles sans détruire les rayons, qui sont réutilisés par les abeilles."},
  {"id":"q_a7_b","skill":"apiculture","node":"a7","stmt":"Un miel trop humide risque de fermenter sous l'action de levures.","truth":true,"explain":"Vrai. Au-dessus d'un certain taux d'humidité, les levures osmophiles font fermenter le miel."},
  {"id":"q_a7_c","skill":"apiculture","node":"a7","stmt":"Une reine vierge se féconde avec un seul mâle.","truth":false,"explain":"Faux. Elle s'accouple en vol avec plusieurs mâles (polyandrie), ce qui diversifie la génétique de la colonie."},
  {"id":"q_b1_a","skill":"bois","node":"b1","stmt":"Les poussières fines de bois sont préoccupantes pour la santé en exposition prolongée.","truth":true,"explain":"Vrai. Certaines essences sont classées à risque ; masque adapté et aspiration à la source s'imposent."},
  {"id":"q_b1_b","skill":"bois","node":"b1","stmt":"Un atelier encombré et un sol jonché de copeaux n'augmentent pas le risque d'accident.","truth":false,"explain":"Faux. Désordre et copeaux glissants sont des causes fréquentes d'accident. Un atelier rangé est plus sûr."},
  {"id":"q_b1_c","skill":"bois","node":"b1","stmt":"L'exposition au bruit des machines a un effet cumulatif et irréversible sur l'audition.","truth":true,"explain":"Vrai. D'où la protection auditive : les dommages s'accumulent et ne se réparent pas."},
  {"id":"q_b2_a","skill":"bois","node":"b2","stmt":"Une scie à denture de tronçonnage est optimisée pour couper dans le sens du fil.","truth":false,"explain":"Faux. Le tronçonnage coupe EN TRAVERS du fil ; la refente coupe dans le sens du fil. Dentures différentes."},
  {"id":"q_b2_b","skill":"bois","node":"b2","stmt":"Un angle de taillant faible coupe finement mais s'émousse plus vite.","truth":true,"explain":"Vrai. Tranchant aigu = coupe fine mais fragile ; angle ouvert = robuste mais demande plus d'effort."},
  {"id":"q_b2_c","skill":"bois","node":"b2","stmt":"Le pas d'une scie (dents par pouce) n'a aucune influence sur la finesse de coupe.","truth":false,"explain":"Faux. Peu de dents = coupe rapide et grossière ; beaucoup de dents = coupe lente et nette."},
  {"id":"q_b3_a","skill":"bois","node":"b3","stmt":"Le trusquin trace une ligne parallèle à un chant, à distance constante.","truth":true,"explain":"Vrai. Indispensable pour marquer épaulements de tenon et profondeurs de mortaise de façon régulière."},
  {"id":"q_b3_b","skill":"bois","node":"b3","stmt":"Une équerre faussée n'a pas d'incidence grave sur l'ouvrage.","truth":false,"explain":"Faux. Une équerre fausse propage l'erreur partout. On la vérifie (test du trait retourné)."},
  {"id":"q_b3_c","skill":"bois","node":"b3","stmt":"On garde une surcote (quelques mm) lors du débit pour les ajustements.","truth":true,"explain":"Vrai. La surcote permet le corroyage et les ajustements finaux ; on ne débite pas à la cote exacte."},
  {"id":"q_b5_a","skill":"bois","node":"b5","stmt":"La queue d'aronde résiste mécaniquement à la traction dans un sens.","truth":true,"explain":"Vrai. Son profil trapézoïdal verrouille l'assemblage : assemblage roi des tiroirs et caisses."},
  {"id":"q_b5_b","skill":"bois","node":"b5","stmt":"Un tenon trop serré ne présente aucun risque pour la mortaise.","truth":false,"explain":"Faux. Trop serré, il fend la mortaise sous la pression de la colle (effet de coin hydraulique)."},
  {"id":"q_b5_c","skill":"bois","node":"b5","stmt":"Une règle courante donne un tenon d'environ 1/3 de l'épaisseur de la pièce.","truth":true,"explain":"Vrai. Ce ratio équilibre la résistance du tenon et celle des joues de la mortaise."},
  {"id":"q_b6_a","skill":"bois","node":"b6","stmt":"Avec une colle adaptée et un bon ajustage, le joint peut être plus résistant que le bois.","truth":true,"explain":"Vrai. La rupture survient alors dans la fibre, pas dans le joint — à condition d'un bon contact."},
  {"id":"q_b6_b","skill":"bois","node":"b6","stmt":"Un bois bruni ou gras se colle aussi bien qu'un bois fraîchement travaillé.","truth":false,"explain":"Faux. Le collage exige le mouillage : un bois lisse/gras/poussiéreux empêche la colle de pénétrer."},
  {"id":"q_b6_c","skill":"bois","node":"b6","stmt":"Une bavure de colle sèche peut empêcher la finition de pénétrer (tache claire).","truth":true,"explain":"Vrai. On essuie les bavures fraîches : sèche, la colle bloque le vernis/l'huile localement."},
  {"id":"q_b7_a","skill":"bois","node":"b7","stmt":"Le bois bouge surtout en longueur avec l'humidité.","truth":false,"explain":"Faux. Le mouvement est quasi nul en longueur ; il est maximal en largeur (tangentiel)."},
  {"id":"q_b7_b","skill":"bois","node":"b7","stmt":"Une huile pénètre le bois alors qu'un vernis forme un film en surface.","truth":true,"explain":"Vrai. Huiles = pénétration, réparables ; vernis = film protecteur, réparation plus difficile."},
  {"id":"q_b7_c","skill":"bois","node":"b7","stmt":"Un bois pas assez sec bougera énormément en séchant chez son propriétaire.","truth":true,"explain":"Vrai. Un bois trop humide au montage se rétracte ensuite : on travaille un bois stabilisé au taux d'équilibre."},
  {"id":"q_h1_a","skill":"cheval","node":"h1","stmt":"La zone la plus dangereuse autour d'un cheval est son arrière-train.","truth":true,"explain":"Vrai. Une ruade de l'arrière-train peut projeter une force considérable ; c'est la zone à ne jamais approcher sans avertir."},
  {"id":"q_h1_b","skill":"cheval","node":"h1","stmt":"Pour approcher un cheval, on s'avance directement face à lui dans l'axe de la tête.","truth":false,"explain":"Faux. On approche par l'épaule, côté frontal latéral : jamais en plein face (angle mort devant le nez) ni par derrière."},
  {"id":"q_h1_c","skill":"cheval","node":"h1","stmt":"Voir le blanc de l'œil (sclère) chez un cheval est souvent signe de stress ou de peur.","truth":true,"explain":"Vrai. Le blanc de l'œil visible signale une activation du système nerveux : le cheval est en alerte."},
  {"id":"q_h1_d","skill":"cheval","node":"h1","stmt":"Un cheval qui plaque les oreilles en arrière envoie un signal d'avertissement.","truth":true,"explain":"Vrai. Oreilles plaquées = signal fort d'irritation ou de peur. Ne jamais ignorer ce signal."},
  {"id":"q_h1_e","skill":"cheval","node":"h1","stmt":"Si un cheval tourne sa croupe vers toi, il veut jouer et se faire gratter.","truth":false,"explain":"Faux. C'est un signal d'avertissement : le cheval demande de l'espace. S'éloigner est la bonne réponse."},
  {"id":"q_h1_f","skill":"cheval","node":"h1","stmt":"Dans la grande majorité des cas, un cheval donne des signaux avant de ruer.","truth":true,"explain":"Vrai. Les oreilles plaquées, la queue battante, le regard fixe sont des avertissements. Lire ces signaux prévient l'incident."},
  {"id":"q_h2_a","skill":"cheval","node":"h2","stmt":"Le cheval est un animal prédateur, ce qui explique sa grande réactivité aux stimuli.","truth":false,"explain":"Faux. Le cheval est une proie. Sa réactivité vient de son système nerveux câblé pour détecter et fuir le danger."},
  {"id":"q_h2_b","skill":"cheval","node":"h2","stmt":"En liberté, un cheval peut parcourir entre 15 et 25 km par jour.","truth":true,"explain":"Vrai. Le cheval est conçu pour le mouvement continu ; l'immobilité prolongée génère du stress physique et comportemental."},
  {"id":"q_h2_c","skill":"cheval","node":"h2","stmt":"La fuite est le principal mécanisme de défense du cheval face au danger perçu.","truth":true,"explain":"Vrai. Animal proie, il fuit en premier. Cette réaction est automatique (amygdalienne) et précède l'analyse consciente."},
  {"id":"q_h2_d","skill":"cheval","node":"h2","stmt":"Un cheval isolé en box permanent ne développe aucun comportement particulier.","truth":false,"explain":"Faux. L'isolement prolongé peut provoquer des stéréotypies (tics, balancement) : le cheval est un animal social."},
  {"id":"q_h2_e","skill":"cheval","node":"h2","stmt":"Un cheval très stressé apprend mieux car il est hyperalerte.","truth":false,"explain":"Faux. Le cortisol réduit la capacité d'apprentissage. Au-dessus du seuil d'alerte, le cheval ne peut plus mémoriser positivement."},
  {"id":"q_h3_a","skill":"cheval","node":"h3","stmt":"Des oreilles pointées franchement vers l'avant indiquent un cheval attentif à quelque chose devant lui.","truth":true,"explain":"Vrai. Oreilles avant = vigilance, curiosité, attention focalisée sur un point précis."},
  {"id":"q_h3_b","skill":"cheval","node":"h3","stmt":"Une queue levée verticalement indique toujours que le cheval a peur.","truth":false,"explain":"Faux. Une queue levée peut aussi signifier l'excitation ou le jeu (pas seulement la peur). Contexte et autres signaux comptent."},
  {"id":"q_h3_c","skill":"cheval","node":"h3","stmt":"Un bâillement chez le cheval signifie presque toujours qu'il a sommeil.","truth":false,"explain":"Faux. Chez le cheval, le bâillement est souvent un signal de libération de tension (après un exercice ou du stress)."},
  {"id":"q_h3_d","skill":"cheval","node":"h3","stmt":"Un ébrouement (souffle brusque par les naseaux) peut signaler une libération de tension.","truth":true,"explain":"Vrai. L'ébrouement est un signal parasympathique : le stress redescend. Les entraîneurs R+ l'attendent activement."},
  {"id":"q_h3_e","skill":"cheval","node":"h3","stmt":"Un cheval qui mastique dans le vide après un exercice est souvent en train de s'apaiser.","truth":true,"explain":"Vrai. Mastication dans le vide = signal d'apaisement, souvent accompagné d'un baissement de tête."},
  {"id":"q_h4_a","skill":"cheval","node":"h4","stmt":"Le renforcement positif consiste à ajouter quelque chose d'agréable juste après un comportement souhaité.","truth":true,"explain":"Vrai. R+ = ajouter (+) un stimulus agréable pour augmenter la probabilité que le comportement se répète."},
  {"id":"q_h4_b","skill":"cheval","node":"h4","stmt":"Le marqueur conditionné (clic) doit être donné après la friandise pour signaler la fin de l'exercice.","truth":false,"explain":"Faux. Le marqueur est donné AVANT la friandise, au moment précis du bon comportement. Il annonce la récompense à venir."},
  {"id":"q_h4_c","skill":"cheval","node":"h4","stmt":"En R+, on récompense uniquement les comportements parfaitement réalisés dès le début.","truth":false,"explain":"Faux. On récompense les approximations successives (shaping). Attendre la perfection bloque tout apprentissage."},
  {"id":"q_h4_d","skill":"cheval","node":"h4","stmt":"Le timing du marqueur est crucial : même 2 secondes de décalage peuvent marquer le mauvais comportement.","truth":true,"explain":"Vrai. Le cheval associe la récompense à ce qu'il faisait au moment du marqueur, même si ce n'est pas ce qu'on cherchait."},
  {"id":"q_h4_e","skill":"cheval","node":"h4","stmt":"Un marqueur conditionné reste efficace même sans jamais être suivi d'un renforçateur primaire.","truth":false,"explain":"Faux. Le marqueur doit être maintenu par l'association régulière avec le renforçateur primaire, sinon il s'éteint."},
  {"id":"q_h5_a","skill":"cheval","node":"h5","stmt":"Le shaping consiste à récompenser des approximations successives vers le comportement cible.","truth":true,"explain":"Vrai. On récompense la version grossière, puis on élève le critère pas à pas jusqu'au comportement final voulu."},
  {"id":"q_h5_b","skill":"cheval","node":"h5","stmt":"Le targeting apprend au cheval à toucher un objet avec une partie de son corps.","truth":true,"explain":"Vrai. Toucher un bâton avec le nez est souvent le premier comportement enseigné : simple, précis, et adaptable à mille usages."},
  {"id":"q_h5_c","skill":"cheval","node":"h5","stmt":"En shaping, on peut travailler simultanément la durée et la complexité du mouvement.","truth":false,"explain":"Faux. On ne travaille qu'une dimension à la fois : si on augmente la durée, on simplifie la forme, et inversement."},
  {"id":"q_h5_d","skill":"cheval","node":"h5","stmt":"Le chaînage vers l'arrière consiste à apprendre d'abord le dernier élément de la séquence.","truth":true,"explain":"Vrai. On apprend C, puis B→C, puis A→B→C. Le dernier maillon est le plus renforcé."},
  {"id":"q_h5_e","skill":"cheval","node":"h5","stmt":"Si le cheval réussit moins de 80 % des essais, le critère est probablement trop difficile.","truth":true,"explain":"Vrai. Règle des 80 % : en dessous, on revient à une étape plus facile. Taux de succès élevé = motivation haute."},
  {"id":"q_h6_a","skill":"cheval","node":"h6","stmt":"Le flooding (exposition forcée et prolongée) est recommandé pour désensibiliser un cheval très réactif.","truth":false,"explain":"Faux. Le flooding provoque de la résignation apprise, pas de l'habituation. Il peut traumatiser durablement."},
  {"id":"q_h6_b","skill":"cheval","node":"h6","stmt":"La méthode approche-retraite consiste à retirer le stimulus avant que le cheval ne dépasse son seuil.","truth":true,"explain":"Vrai. On retire le stimulus dès le premier signe de reconnaissance (avant l'affolement) : la retraite EST le renforcement."},
  {"id":"q_h6_c","skill":"cheval","node":"h6","stmt":"Une seule exposition traumatisante intense peut annuler des semaines de travail de désensibilisation.","truth":true,"explain":"Vrai. C'est le « one-trial learning » de la peur : l'amygdale grave une expérience très négative en une seule fois."},
  {"id":"q_h6_d","skill":"cheval","node":"h6","stmt":"En désensibilisation, on commence par le stimulus le plus effrayant pour aller vers le plus faible.","truth":false,"explain":"Faux. On commence par la version la moins effrayante, bien en dessous du seuil d'alerte."},
  {"id":"q_h6_e","skill":"cheval","node":"h6","stmt":"Un cheval qui s'immobilise face au stimulus lors d'un flooding est forcément détendu.","truth":false,"explain":"Faux. Il peut être dans un état de résignation apprise (sidération). Ce n'est pas de la confiance."},
  {"id":"q_h7_a","skill":"cheval","node":"h7","stmt":"Des séances courtes et fréquentes sont généralement plus efficaces que de longues séances rares.","truth":true,"explain":"Vrai. La mémoire consolide entre les sessions. 15-20 min × 4 fois par semaine > une longue séance hebdomadaire."},
  {"id":"q_h7_b","skill":"cheval","node":"h7","stmt":"Un objectif d'entraînement doit être observable et mesurable pour être utile.","truth":true,"explain":"Vrai. « Lever le pied gauche sur signal, 5 secondes, dans 4 semaines » permet de savoir objectivement si on progresse."},
  {"id":"q_h7_c","skill":"cheval","node":"h7","stmt":"En cas de régression soudaine, la bonne réponse est d'insister davantage sur le comportement difficile.","truth":false,"explain":"Faux. On revient à une étape maîtrisée, on finit sur un succès, et on reprend le lendemain. Insister aggrave."},
  {"id":"q_h7_d","skill":"cheval","node":"h7","stmt":"Tenir un journal d'entraînement aide à identifier des patterns sur plusieurs semaines.","truth":true,"explain":"Vrai. Le journal révèle les jours plus productifs, les exercices qui bloquent, et les progrès invisibles au quotidien."},
  {"id":"q_h7_e","skill":"cheval","node":"h7","stmt":"Une séance d'entraînement doit toujours se terminer sur un comportement maîtrisé.","truth":true,"explain":"Vrai. Finir sur un succès ancre une association positive et laisse le cheval dans un bon état émotionnel pour la prochaine séance."},
];

